B.anh=new A.v5("\u0627\u0644\u062f\u0639\u0645 \u0627\u0644\u0641\u0646\u064a","Technical Support","\u0644\u0644\u0645\u0633\u0627\u0639\u062f\u0629 \u0627\u0644\u0641\u0646\u064a\u0629 \u0627\u0644\u0645\u062a\u0639\u0644\u0642\u0629 \u0628\u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0623\u0648 \u0627\u0644\u0637\u0644\u0628\u0627\u062a\u060c \u062a\u0648\u0627\u0635\u0644 \u0645\u0639 \u0641\u0631\u064a\u0642 \u0627\u0644\u062f\u0639\u0645 \u0639\u0628\u0631:\n\u0627\u0644\u0628\u0631\u064a\u062f: support@delivery-mat3mk.com\n\u0627\u0644\u0647\u0627\u062a\u0641: +20 100 000 0000\n\u0633\u0627\u0639\u0627\u062a \u0627\u0644\u062f\u0639\u0645: \u064a\u0648\u0645\u064a\u064b\u0627 \u0645\u0646 10:00 \u0635\u0628\u0627\u062d\u064b\u0627 \u062d\u062a\u0649 10:00 \u0645\u0633\u0627\u0621\u064b.\n\u064a\u0631\u062c\u0649 \u0625\u0631\u0641\u0627\u0642 \u0631\u0642\u0645 \u0627\u0644\u0637\u0644\u0628 \u0648\u0648\u0635\u0641 \u0648\u0627\u0636\u062d \u0644\u0644\u0645\u0634\u0643\u0644\u0629 \u0644\u062a\u0633\u0631\u064a\u0639 \u0627\u0644\u0645\u0639\u0627\u0644\u062c\u0629.","For technical assistance related to the app or orders, contact support:\nEmail: support@delivery-mat3mk.com\nPhone: +20 100 000 0000\nSupport hours: Daily from 10:00 AM to 10:00 PM.\nPlease include your order number and a clear issue description.")
B.anj=new A.v5("\u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629","Privacy Policy","\u0646\u0644\u062a\u0632\u0645 \u0628\u062d\u0645\u0627\u064a\u0629 \u0628\u064a\u0627\u0646\u0627\u062a\u0643 \u0627\u0644\u0634\u062e\u0635\u064a\u0629. \u0646\u0633\u062a\u062e\u062f\u0645 \u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0644\u062d\u0633\u0627\u0628 \u0648\u0627\u0644\u0639\u0646\u0648\u0627\u0646 \u0641\u0642\u0637 \u0644\u062a\u0642\u062f\u064a\u0645 \u0627\u0644\u062e\u062f\u0645\u0629 \u0648\u062a\u062d\u0633\u064a\u0646 \u062c\u0648\u062f\u0629 \u0627\u0644\u0637\u0644\u0628\u0627\u062a.\n\u0644\u0627 \u0646\u0634\u0627\u0631\u0643 \u0645\u0639\u0644\u0648\u0645\u0627\u062a\u0643 \u0645\u0639 \u0623\u064a \u0637\u0631\u0641 \u062b\u0627\u0644\u062b \u062e\u0627\u0631\u062c \u0646\u0637\u0627\u0642 \u0627\u0644\u062a\u0634\u063a\u064a\u0644 \u0623\u0648 \u0627\u0644\u0645\u062a\u0637\u0644\u0628\u0627\u062a \u0627\u0644\u0642\u0627\u0646\u0648\u0646\u064a\u0629.\n\u064a\u0645\u0643\u0646\u0643 \u0637\u0644\u0628 \u062a\u062d\u062f\u064a\u062b \u0623\u0648 \u062d\u0630\u0641 \u0628\u064a\u0627\u0646\u0627\u062a\u0643 \u0627\u0644\u0634\u062e\u0635\u064a\u0629 \u0645\u0646 \u062e\u0644\u0627\u0644 \u0627\u0644\u062f\u0639\u0645 \u0627\u0644\u0641\u0646\u064a.","We are committed to protecting your personal data. Account and address data are used only to provide service and improve order quality.\nWe do not share your information with third parties outside operational or legal requirements.\nYou may request data updates or deletion through technical support.")
B.ang=new A.v5("\u0627\u0644\u062d\u0645\u0627\u064a\u0629 \u0648\u0627\u0644\u0623\u0645\u0627\u0646","Protection & Security","\u0646\u0637\u0628\u0642 \u0636\u0648\u0627\u0628\u0637 \u0623\u0645\u0627\u0646 \u062a\u0634\u063a\u064a\u0644\u064a\u0629 \u0644\u062d\u0645\u0627\u064a\u0629 \u0627\u0644\u062d\u0633\u0627\u0628\u0627\u062a \u0648\u0627\u0644\u0627\u062a\u0635\u0627\u0644\u0627\u062a \u062f\u0627\u062e\u0644 \u0627\u0644\u062a\u0637\u0628\u064a\u0642.\n\u064a\u062a\u0645 \u0645\u0631\u0627\u0642\u0628\u0629 \u0627\u0644\u0623\u062e\u0637\u0627\u0621 \u0627\u0644\u0641\u0646\u064a\u0629 \u0648\u0645\u062d\u0627\u0648\u0644\u0627\u062a \u0627\u0644\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u063a\u064a\u0631 \u0627\u0644\u0645\u0639\u062a\u0627\u062f \u0644\u062a\u062d\u0633\u064a\u0646 \u0627\u0644\u0623\u0645\u0627\u0646 \u0648\u0627\u0644\u0627\u0633\u062a\u0642\u0631\u0627\u0631.\n\u0646\u0646\u0635\u062d \u0628\u0639\u062f\u0645 \u0645\u0634\u0627\u0631\u0643\u0629 \u0631\u0645\u0632 \u0627\u0644\u062a\u062d\u0642\u0642 \u0623\u0648 \u0628\u064a\u0627\u0646\u0627\u062a \u062a\u0633\u062c\u064a\u0644 \u0627\u0644\u062f\u062e\u0648\u0644 \u0645\u0639 \u0623\u064a \u062c\u0647\u0629.","We apply operational security controls to protect accounts and in-app communication.\nTechnical errors and unusual activity are monitored to improve security and stability.\nDo not share verification codes or login credentials with anyone.")
